(function(){
  var $=function(id){return document.getElementById(id);};
  var fmt=function(n){return '$'+Math.round(n).toLocaleString('en-US');};
  function pmt(loan,rate,term){var r=rate/100/12,n=term*12; return r>0? loan*r*Math.pow(1+r,n)/(Math.pow(1+r,n)-1): loan/n;}
  function monthly(price,downPct,rate){
    var down=price*downPct/100, base=price-down, ufmip=base*0.0175, loan=base+ufmip;
    var pi=pmt(loan,rate,30), mip=loan*0.0055/12, tax=price*0.01/12, ins=price*0.006/12;
    return {total:pi+mip+tax+ins, loan:loan, down:down};
  }
  function calc(){
    var inc=+$('affIncome').value||0, debts=+$('affDebts').value||0;
    var downPct=+$('affDownPct').value||3.5, rate=+$('affRate').value||6.5;
    var mInc=inc/12;
    var maxHousing=Math.max(0, Math.min(mInc*0.31, mInc*0.43-debts));
    var lo=0, hi=5000000, best=0, info={loan:0,down:0};
    for(var i=0;i<40;i++){var mid=(lo+hi)/2; var m=monthly(mid,downPct,rate);
      if(m.total<=maxHousing){best=mid;info=m;lo=mid;}else{hi=mid;}}
    $('affPrice').innerHTML=fmt(best);
    $('affHousing').textContent=fmt(maxHousing)+'/mo';
    $('affLoan').textContent=fmt(info.loan);
    $('affDown').textContent=fmt(info.down);
  }
  ['affIncome','affDebts','affDownPct','affRate'].forEach(function(id){$(id).addEventListener('input',calc);});
  calc();
})();
